    return try {
        val python = Python.getInstance()
        val executor = python.getModule("executor")

        client.newCall(request).execute().use { response ->
            val raw = response.body?.string() ?: ""
            val jsonResp = JSONObject(raw)
            val candidates = jsonResp.optJSONArray("candidates") ?: return "AI did not return a valid response."
            val content = candidates.getJSONObject(0).getJSONObject("content")
            val parts = content.getJSONArray("parts")

            var finalResponse = ""

            for (i in 0 until parts.length()) {
                val part = parts.getJSONObject(i)

                // Handle Text Response
                if (part.has("text")) {
                    finalResponse += part.getString("text") + "\n"
                }

                // Handle Function Call (The Logic Bridge)
                if (part.has("functionCall")) {
                    val call = part.getJSONObject("functionCall")
                    if (call.getString("name") == "execute_python_code") {
                        val code = call.getJSONObject("args").getString("code")
                        finalResponse += "\n[Executing Script...]\n"
                        val result = executor.callAttr("run_code", code).toString()
                        finalResponse += "\nOutput:\n$result"
                    }
                }
            }
            finalResponse.trim()
        }
    } catch (e: Exception) {
        "Connection Error: ${e.message}"
    }
}
